{
  "mitigation_currently_implemented": "Configure the Squid proxy server to enforce web filtering policies blocking or limiting HTTP/HTTPS traffic from UbuntuComputer to untrusted or suspicious external websites to prevent attacker C2 communications and exfiltration",
  "comments": "Unable to configure proxy policies on the FortiGate firewall to filter traffic from UbuntuComputer, so I applied host-based egress filtering on the UbuntuComputer using iptables to reject outbound HTTP (port 80) and HTTPS (port 443) traffic. This prevents the compromised host from establishing outbound web connections, effectively disrupting communications such as C2 and exfiltration over HTTP/HTTPS. This complements the previous firewall policy blocking direct traffic to the attacker's IP. While this is a host-level mitigation, it stops the exfiltration attempts without removing the compromised host from the network.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "iptables -A OUTPUT -p tcp --dport 80 -j REJECT",
    "iptables -A OUTPUT -p tcp --dport 443 -j REJECT"
  ]
}

{
  "mitigation_currently_implemented": "Implement strict host-based monitoring and alerting on UbuntuComputer for suspicious file access and staging activities using available system tools and cron job monitoring",
  "comments": "I created a cron job on UbuntuComputer to monitor the directory /usr/src/app/staged for any new or modified files every minute. The cron job computes SHA256 hashes of new files and appends them to a log at /var/log/file_monitor.log. Additionally, every 5 minutes another cron job checks this log for any entries indicating suspicious staging activity and triggers a system log alert. This host-based monitoring increases visibility into potentially malicious file staging used by the attacker, allowing alerting without host quarantine or reimaging.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "echo '* * * * * root find /usr/src/app/staged -type f -mmin -1 -print | xargs -r sha256sum >> /var/log/file_monitor.log' > /etc/cron.d/file_monitor",
    "echo '*/5 * * * * root grep -q \"staged\" /var/log/file_monitor.log && logger -p authpriv.info \"Alert: Suspicious file staging activity detected\"' >> /etc/cron.d/file_monitor"
  ]
}

{
  "mitigation_currently_implemented": "Harden file system permissions on the UbuntuComputer to restrict unauthorized access and copying of sensitive files, limiting the attacker's ability to collect and stage data",
  "comments": "I hardened the file system permissions on the UbuntuComputer by removing read, write, and execute permissions for others (non-owner and non-group users) on directories containing sensitive files (/usr/share/pixmaps, /usr/share/icons) and the staging directory (/usr/src/app/staged). This restricts unauthorized access and copying of these files by the attacker, reducing their ability to collect and stage data for exfiltration, while keeping the compromised host active on the network.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "chmod -R o-rwx /usr/share/pixmaps /usr/share/icons /usr/src/app/staged"
  ]
}

{
  "mitigation_currently_implemented": "Maintain the current tightened file system permissions on the UbuntuComputer to continuously prevent unauthorized access and staging of sensitive files",
  "comments": "The current file system permissions on UbuntuComputer have been tightened to restrict unauthorized access to sensitive files and the staging directory. This mitigation will be maintained continuously as it effectively limits the attacker's ability to access and stage data for exfiltration. Maintaining these permissions is critical for ongoing defense while the attacker remains in the environment.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "chmod -R o-rwx /usr/share/pixmaps /usr/share/icons /usr/src/app/staged"
  ]
}

{
